            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/account/tax-forms"]""",
            Tags = """["compliance","walkthrough"]""",
            ContentJson = """{"appRoute":"/account/tax-forms","startButtonLabel":"Tour Compliance Forms","steps":[{"element":".tax-forms__item","popover":{"title":"Form Card","description":"Each form shows up as a card with its name, a short description, and where it stands. A green check means it's done, and the date you finished it appears on the right. Forms you must finish before you can be assigned to jobs show a colored 'Required' badge.","side":"bottom"}},{"element":".account-page__title","popover":{"title":"Completion Indicator","description":"Each card shows an icon that tells you at a glance where the form stands. Not started yet shows the form's own icon; a green check means it's finished. Scan down the list to see your status.","side":"right"}},{"element":".tax-forms__intro","popover":{"title":"Open a Form","description":"Click anywhere on a form's card to open it. If you still need to complete it, this takes you into the guided onboarding steps; if it's already done, it opens a summary of what you submitted.","side":"left"}},{"element":".tax-forms__item--complete","popover":{"title":"Completed Form","description":"A finished form shows a green edge, a check, and the date you completed it. Click it to review what you submitted, download your signed copy, or make changes where allowed. Note that the I-9 can't be changed once submitted.","side":"bottom"}}]}"""
