            Summary = "The employer-side workflow on Admin > Compliance: pick an employee, review their per-employee compliance panel (form submissions with statuses and I-9 sub-states, identity documents, pay stubs, tax docs), verify uploaded identity documents, download signed PDFs, and send a compliance reminder.",
            ContentType = TrainingContentType.Article,
