            Summary = "The employer's responsibility on the I-9: after the employee signs Section 1, an Admin/Manager/Office Manager completes Section 2 within 3 business days by recording the inspected identity documents (List A, or List B + List C) and any work-authorization expiration for reverification.",
            ContentType = TrainingContentType.Article,
