            ContentJson = """{"title":"Compliance Admin Field Reference","groups":[{"heading":"Access & Location","items":[{"label":"Where","value":"The Compliance area of the Admin section. It opens on the form-templates list, and it's the first screen Managers and Office Managers land on."},{"label":"When it's available","value":"Only when compliance forms are turned on for your company. If they're off, the whole Compliance area is hidden."},{"label":"Who can manage templates","value":"Creating, editing, and deleting form templates is limited to Admins."},{"label":"Who can review employees","value":"Reviewing an employee's forms, verifying ID documents, sending reminders, and finishing the employer part of the I-9 are open to Admins, Managers, and Office Managers."}]},{"heading":"Templates Panel","items":[{"label":"Sync All","value":"Re-checks the source document for every form set to update automatically, so they all pick up the latest version at once."},{"label":"New Template","value":"Creates a new custom form template."},{"label":"Needs-setup label","value":"A colored label next to a form that still needs its fillable layout built before employees can complete it."},{"label":"Auto / Manual label","value":"Shows whether the form updates itself from its source document or only when you refresh it by hand."},{"label":"Last Synced","value":"When the form last picked up its source document, or 'Never' if it hasn't yet."},{"label":"Active / Inactive","value":"Whether employees can see the form on their own Tax Forms page."},{"label":"Built-in form","value":"The six standard forms (W-4, I-9, state withholding, direct deposit, workers' comp, handbook). These can't be deleted, and editing them only lets you attach a document, not rename them."},{"label":"Custom form","value":"A form you created yourself. You can fully edit it and delete it."}]},{"heading":"Template Create/Edit Fields","items":[{"label":"Name","value":"The form's display name (required)."},{"label":"Form Type","value":"Which kind of form this is: W-4, I-9, state withholding, direct deposit, workers' comp, or handbook (required)."},{"label":"Description","value":"A short line shown under the name on the employee's card."},{"label":"Icon","value":"The small picture shown next to the form (required)."},{"label":"Completion Key","value":"Ties this form to a step in the employee's onboarding progress and job-eligibility check (required)."},{"label":"Source URL","value":"The web address of the official government PDF. Needed if you want the system to build the fillable layout or keep the form up to date automatically."},{"label":"Sort Order","value":"Where the form appears in the employee's list."},{"label":"Update automatically","value":"Re-checks the source document on a schedule and pulls in any new version."},{"label":"Active","value":"Makes the form visible to employees."},{"label":"Requires ID documents","value":"Turns on the List A / B / C upload window. Used by the I-9."},{"label":"Required before jobs","value":"An unfinished form blocks the employee from being assigned to production jobs and shows them a 'Required' badge."},{"label":"PDF field mapping","value":"Matches the answers employees give to the right blanks on the official PDF, so their signed copy comes out correctly filled in."}]},{"heading":"Extract / Sync / Pending Setup","items":[{"label":"Build the fillable form","value":"Turns the official PDF into an on-screen form employees can fill out. Available once the form has a source document. It appears only until the form is built."},{"label":"Needs-setup state","value":"A form that still needs to be built. It shows the needs-setup label, and employees see a 'not ready yet' message until you build it."},{"label":"Refresh one form","value":"Re-checks the source document for a single form, instead of doing all of them at once."},{"label":"Attach a blank PDF","value":"For built-in forms, attach the blank official PDF and its field mapping so signed copies come out correctly filled in. A colored mark confirms the PDF is attached."}]},{"heading":"State Withholding Dialog","items":[{"label":"How to open","value":"On the templates list, open the state withholding row to see the state-by-state setup board."},{"label":"Ready to sign","value":"States that have their own form and are fully built. Employees there get the full on-screen fill-and-sign experience."},{"label":"Needs a PDF","value":"States that have their own form but aren't built yet. Employees there are stuck until you upload the state's PDF and build it. This is your to-do list."},{"label":"Uses the federal W-4","value":"States that don't have their own form and rely on the federal W-4 instead. Employees there fill out nothing extra."},{"label":"No state income tax","value":"States with no income tax, such as Texas, Florida, and Nevada. Employees there fill out nothing."},{"label":"How a state is chosen","value":"An employee's state form is decided by their work location, not by a menu they pick. No work location falls back to the company's default location."},{"label":"State card","value":"Shows the state, its form name where it has one, and its setup status. The employee's own state is highlighted, and clicking a card selects that state."}]},{"heading":"Per-Employee Review","items":[{"label":"Send Reminder","value":"Notifies the employee to finish any forms they still owe."},{"label":"State summary","value":"A line explaining how the employee's state is handled (no tax, uses the federal W-4, or a named state form) and where that came from."},{"label":"Form status","value":"Where each of the employee's forms stands: started, opened for signing, finished, expired, or declined."},{"label":"I-9 progress","value":"On I-9 rows, shows whether the employee's part and the employer's part are each done."},{"label":"Download signed copy","value":"Pulls a signed form for your records once it exists."},{"label":"Verify ID document","value":"Marks an uploaded ID document as verified after you've checked it against the original. Until then it shows as pending."}]},{"heading":"Complete I-9 Section 2","items":[{"label":"Who & deadline","value":"An Admin, Manager, or Office Manager finishes the employer part within three business days of the employee's first day. The employee must sign their part first."},{"label":"Where to start","value":"The 'Complete Section 2' action on an I-9 row where the employee has signed but the employer part isn't done."},{"label":"Which documents","value":"Pick how the employee proved eligibility: one List A document (proves identity and work authorization), or a List B document (identity) plus a List C document (work authorization)."},{"label":"First Day of Employment","value":"The employee's start date, which sets the three-business-day deadline (required)."},{"label":"Document details","value":"For each document you checked, record its type, number, who issued it, and its expiration date."},{"label":"Work Authorization Expiration","value":"If the employee's work authorization expires, add the date so HR is reminded to renew the check. Leave it blank for documents that don't expire."},{"label":"Can't be changed later","value":"A finished I-9 is a permanent record. Corrections follow the official government process, not an in-app edit."}]}]}"""
